1	/**
2	 * CM6 adapter for the outline keyboard grammar: a high-precedence keymap,
3	 * gated per keypress on outline mode via the public editorInfoField. All
4	 * decisions live in the pure grammar module.
5	 */
6	
7	import { Prec, type Extension } from '@codemirror/state';
8	import { keymap, type EditorView } from '@codemirror/view';
9	import { Notice, editorInfoField } from 'obsidian';
10	import { planKey, type GrammarKey } from './grammar';
11	
12	export interface ModeSource {
13	  isOutline(path: string): boolean;
14	}
15	
16	function makeHandler(modes: ModeSource, key: GrammarKey) {
17	  return (view: EditorView): boolean => {
18	    const info = view.state.field(editorInfoField, false);
19	    const path = info?.file?.path;
20	    if (!path || !modes.isOutline(path)) return false;
21	
22	    const head = view.state.selection.main.head;
23	    const line = view.state.doc.lineAt(head);
24	    const outcome = planKey(view.state.doc.toString(), {
25	      line: line.number - 1,
26	      ch: head - line.from,
27	    }, key);
28	
29	    if (outcome === null) return false;
30	    if ('notice' in outcome) {
31	      new Notice(outcome.notice, 1500);
32	      return true; // consume: stock behavior must not fire on a rejected op
33	    }
34	    const doc = view.state.doc;
35	    view.dispatch({
36	      changes: outcome.plan.changes.map((change) => ({
37	        from: doc.line(change.from.line + 1).from + change.from.ch,
38	        to: doc.line(change.to.line + 1).from + change.to.ch,
39	        insert: change.text,
40	      })),
41	      selection: { anchor: outcome.plan.selection },
42	      userEvent: outcome.plan.userEvent,
43	      scrollIntoView: true,
44	    });
45	    return true;
46	  };
47	}
48	
49	export function grammarExtension(modes: ModeSource): Extension {
50	  return Prec.highest(
51	    keymap.of([
52	      { key: 'Tab', run: makeHandler(modes, 'indent') },
53	      { key: 'Shift-Tab', run: makeHandler(modes, 'outdent') },
54	      { key: 'Alt-ArrowUp', run: makeHandler(modes, 'move-up') },
55	      { key: 'Alt-ArrowDown', run: makeHandler(modes, 'move-down') },
56	      { key: 'Enter', run: makeHandler(modes, 'split') },
57	      { key: 'Shift-Enter', run: makeHandler(modes, 'continue') },
58	    ]),
59	  );
60	}
