9	export function nodeAtLine(doc: OutlineDoc, line: number): OutlineNode | undefined {
10	  let current = doc.preamble.length;
11	  if (line < current) return undefined;
12	  let found: OutlineNode | undefined;
13	  const walk = (node: OutlineNode): void => {
14	    if (found) return;
15	    const end = current + node.lines.length + node.trailingGap.length;
16	    if (line < end) {
17	      found = node;
18	      // Descend no further: children come after this node's own span.
19	      return;
20	    }
21	    current = end;
22	    node.children.forEach(walk);
23	  };
24	  doc.children.forEach(walk);
25	  return found;
26	}
