/**
 * Pure per-line decoration facts for outline mode's visual node chrome: the
 * indentation-guide depth (tree position, not raw markdown indentation/
 * level) and which lines should carry a paragraph leader marker. No CM6
 * imports — the CM6 ViewPlugin in decorations.ts is a thin adapter.
 */

import type { OutlineDoc, OutlineNode } from '../model';

export interface LineDecorationFact {
  /** 0-indexed absolute line number in the document. */
  readonly lineNumber: number;
  /** Distance from the document root; top-level nodes are depth 0. */
  readonly depth: number;
  readonly isParagraphFirstLine: boolean;
}

/**
 * Walks the parsed tree in document order (a node's own lines, then its
 * children — the same layout `nodeAtLine`/`startLine` assume: trailingGap
 * lines sit between a node's own lines and its children, and carry no
 * fact of their own).
 */
export function decorate(doc: OutlineDoc): LineDecorationFact[] {
  const facts: LineDecorationFact[] = [];
  let current = doc.preamble.length;

  const walk = (node: OutlineNode, depth: number): void => {
    for (let i = 0; i < node.lines.length; i++) {
      facts.push({
        lineNumber: current + i,
        depth,
        isParagraphFirstLine: node.kind === 'paragraph' && i === 0,
      });
    }
    current += node.lines.length + node.trailingGap.length;
    node.children.forEach((child) => walk(child, depth + 1));
  };

  doc.children.forEach((node) => walk(node, 0));
  return facts;
}

import { describe, expect, it } from 'vitest';
import { parse } from '../src/parse';
import { decorate } from '../src/plugin/decorate';

describe('decorate: indentation-guide depth', () => {
  it('agrees across heading, list, and paragraph-adjacency encodings', () => {
    const md = [
      '# Top',
      '',
      '## Mid',
      '',
      '### Deep heading',
      '',
      '- item',
      '  - nested item',
      '',
      'Parent para.',
      '- Child para as list item.',
      '',
    ].join('\n');
    const doc = parse(md);
    const facts = decorate(doc);

    // "# Top" depth 0, "## Mid" depth 1, "### Deep heading" depth 2 (tree
    // position, not raw '#' count minus one).
    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));
    expect(byLine.get(0)?.depth).toBe(0); // # Top
    expect(byLine.get(2)?.depth).toBe(1); // ## Mid
    expect(byLine.get(4)?.depth).toBe(2); // ### Deep heading

    // "- item" is a top-level list under "### Deep heading" -> depth 3;
    // "  - nested item" is its child -> depth 4.
    expect(byLine.get(6)?.depth).toBe(3); // - item
    expect(byLine.get(7)?.depth).toBe(4); // nested item

    // Paragraph-adjacency: "Parent para." top-level under the deep heading
    // (depth 3, sibling of "- item"); its list-item-encoded paragraph child
    // is depth 4 - matching the nested list item's depth exactly.
    const parentLine = md.split('\n').indexOf('Parent para.');
    const childLine = md.split('\n').indexOf('- Child para as list item.');
    expect(byLine.get(parentLine)?.depth).toBe(3);
    expect(byLine.get(childLine)?.depth).toBe(4);
  });

  it('excludes trailing gap (blank separator) lines', () => {
    const md = 'First.\n\nSecond.\n';
    const doc = parse(md);
    const facts = decorate(doc);
    const lines = facts.map((f) => f.lineNumber);
    expect(lines).toEqual([0, 2]); // line 1 is the blank gap, no fact
  });

  it('includes multiline node continuation lines at the node’s own depth', () => {
    const md = '- item\n  continuation\n';
    const doc = parse(md);
    const facts = decorate(doc);
    expect(facts.map((f) => f.lineNumber)).toEqual([0, 1]);
    expect(facts[0]!.depth).toBe(0);
    expect(facts[1]!.depth).toBe(0);
  });

  it('produces no facts for an empty document or preamble-only document', () => {
    expect(decorate(parse(''))).toEqual([]);
    expect(decorate(parse('---\nt: 1\n---\n'))).toEqual([]);
  });
});

describe('decorate: paragraph leader marker', () => {
  it('marks only the first line of paragraph nodes', () => {
    const md = 'Para one\nsecond line\n\n- list item\n\n## Heading\n';
    const doc = parse(md);
    const facts = decorate(doc);
    const byLine = new Map(facts.map((f) => [f.lineNumber, f]));

    expect(byLine.get(0)?.isParagraphFirstLine).toBe(true); // "Para one"
    expect(byLine.get(1)?.isParagraphFirstLine).toBe(false); // "second line"
    expect(byLine.get(3)?.isParagraphFirstLine).toBe(false); // "- list item"
    expect(byLine.get(5)?.isParagraphFirstLine).toBe(false); // "## Heading"
  });
});

/**
 * CM6 adapter for outline mode's visual node chrome: indentation guides and
 * the paragraph leader marker. A `ViewPlugin` recomputes a `DecorationSet`
 * from `decorate(parse(...))` on document changes and mode-gate flips; all
 * depth/marker logic lives in the pure decorate.ts module. Purely additive
 * rendering — never dispatches a transaction, never touches the document.
 */

import { Decoration, ViewPlugin, type DecorationSet, type EditorView } from '@codemirror/view';
import { editorInfoField } from 'obsidian';
import { parse } from '../parse';
import { decorate } from './decorate';
import type { ModeSource } from './keymap';

function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
  const info = view.state.field(editorInfoField, false);
  const path = info?.file?.path;
  if (!path || !modes.isOutline(path)) return Decoration.none;

  const doc = parse(view.state.doc.toString());
  const facts = decorate(doc);
  if (facts.length === 0) return Decoration.none;

  const lineCount = view.state.doc.lines;
  const decorations = facts
    .filter((fact) => fact.lineNumber < lineCount)
    .map((fact) => {
      const line = view.state.doc.line(fact.lineNumber + 1);
      const classes = ['to-node-line'];
      if (fact.isParagraphFirstLine) classes.push('to-node-marker');
      return Decoration.line({
        attributes: {
          class: classes.join(' '),
          style: `--to-depth: ${fact.depth}`,
        },
      }).range(line.from);
    });

  return Decoration.set(decorations, true);
}

export function decorationsExtension(modes: ModeSource) {
  return ViewPlugin.fromClass(
    class {
      decorations: DecorationSet;

      constructor(view: EditorView) {
        this.decorations = buildDecorations(view, modes);
      }

      update(update: { view: EditorView; docChanged: boolean }): void {
        if (update.docChanged) {
          this.decorations = buildDecorations(update.view, modes);
        }
      }
    },
    {
      decorations: (plugin) => plugin.decorations,
    },
  );
}

