/* Outline mode node chrome: indentation guides (by tree depth, not raw
   markdown indentation) and the paragraph leader marker. Both render off a
   single --to-depth custom property set per line by decorations.ts — no
   discrete per-depth classes, so nesting depth is unbounded. Anchored to
   Obsidian's own --list-indent variable so guide spacing matches the
   theme's native list indentation. */

.to-node-line {
	position: relative;
	padding-left: calc(var(--to-depth, 0) * var(--list-indent, 2em));
}

.to-node-line::before {
	content: '';
	position: absolute;
	top: 0;
	bottom: 0;
	left: calc(0.5em - 1px);
	width: 1px;
	background-color: var(--background-modifier-border);
	opacity: calc(min(var(--to-depth, 0), 1));
}

.to-node-marker::before {
	content: '\2022'; /* • */
	position: absolute;
	top: 0;
	left: calc(var(--to-depth, 0) * var(--list-indent, 2em) - 1.2em);
	width: 1em;
	text-align: center;
	color: var(--text-faint);
	background: transparent;
	opacity: 1;
}

