2	 * CM6 adapter for outline mode's visual node chrome: indentation guides and
3	 * the paragraph leader marker. A `ViewPlugin` recomputes a `DecorationSet`
4	 * from `decorate(parse(...))` on document changes and mode-gate flips; all
5	 * depth/marker logic lives in the pure decorate.ts module. Purely additive
6	 * rendering — never dispatches a transaction, never touches the document.
7	 */
8	
9	import {
10	  Decoration,
11	  ViewPlugin,
12	  type DecorationSet,
13	  type EditorView,
14	  type ViewUpdate,
15	} from '@codemirror/view';
16	import { editorInfoField } from 'obsidian';
17	import { parse } from '../parse';
18	import { decorate } from './decorate';
19	import type { ModeSource } from './keymap';
20	
21	function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
22	  const info = view.state.field(editorInfoField, false);
23	  const path = info?.file?.path;
24	  if (!path || !modes.isOutline(path)) return Decoration.none;
25	
26	  const doc = parse(view.state.doc.toString());
27	  const facts = decorate(doc);
28	  if (facts.length === 0) return Decoration.none;
29	
30	  const lineCount = view.state.doc.lines;
31	  const decorations = facts
32	    .filter((fact) => fact.lineNumber < lineCount)
33	    .map((fact) => {
34	      const line = view.state.doc.line(fact.lineNumber + 1);
35	      const classes = ['to-node-line'];
36	      if (fact.isParagraphFirstLine) classes.push('to-node-marker');
37	      return Decoration.line({
38	        attributes: {
39	          class: classes.join(' '),
40	          style: `--to-depth: ${fact.depth}`,
41	        },
42	      }).range(line.from);
43	    });
44	
45	  return Decoration.set(decorations, true);
46	}
47	
48	export function decorationsExtension(modes: ModeSource) {
49	  return ViewPlugin.fromClass(
50	    class {
51	      decorations: DecorationSet;
52	
53	      constructor(view: EditorView) {
54	        this.decorations = buildDecorations(view, modes);
55	      }
56	
57	      // Recompute on every view update, not just docChanged: the mode gate
58	      // can flip out-of-band (plugin data, not a CM6 transaction), and the
59	      // public poke for that — Editor.refresh() — surfaces as a ViewUpdate
60	      // that may carry no document change.
61	      update(update: ViewUpdate): void {
62	        this.decorations = buildDecorations(update.view, modes);
63	      }
64	    },
65	    {
66	      decorations: (plugin) => plugin.decorations,
67	    },
68	  );
