/* Outline mode node chrome: indentation guides (by tree depth, not raw
   markdown indentation) and the paragraph leader marker. Both render off a
   single --to-depth custom property set per line by decorations.ts — no
   discrete per-depth classes, so nesting depth is unbounded.

   --to-indent-unit is a fixed rem value, not Obsidian's em-based
   --list-indent: em resolves against each line's OWN font size, and
   headings render at a larger font than paragraphs/list items, so the same
   tree depth would otherwise draw a different pixel offset per node kind —
   defeating the point of a depth-based guide. rem is root-relative and
   stays fixed regardless of the line's local font size.

   Both rules need !important: Obsidian's own line styling sets padding via
   an equal-or-higher-specificity rule later in the cascade (verified: a
   plain class selector on .cm-line without !important was silently
   overridden, even on lines with none of Obsidian's own inline padding). */

:root {
	--to-indent-unit: 1.5rem;
}

.cm-editor .cm-line.to-node-line {
	position: relative;
	padding-left: calc(var(--to-depth, 0) * var(--to-indent-unit)) !important;
}

.cm-editor .cm-line.to-node-line::before {
	content: '';
	position: absolute;
	top: 0;
	bottom: 0;
	left: calc(0.5 * var(--to-indent-unit) - 1px);
	width: 1px;
	background-color: var(--background-modifier-border);
	opacity: calc(min(var(--to-depth, 0), 1));
}

.cm-editor .cm-line.to-node-marker::after {
	content: '\2022'; /* • */
	position: absolute;
	top: 0;
	left: calc(var(--to-depth, 0) * var(--to-indent-unit) - 1.2rem);
	width: 1rem;
	text-align: center;
	color: var(--text-faint);
	background: transparent;
}

