1	/**
2	 * Pure per-line decoration facts for outline mode's visual node chrome: the
3	 * indentation-guide depth (tree position, not raw markdown indentation/
4	 * level) and which lines should carry a paragraph leader marker. No CM6
5	 * imports — the CM6 ViewPlugin in decorations.ts is a thin adapter.
6	 */
7	
8	import type { OutlineDoc, OutlineNode } from '../model';
9	
10	export interface LineDecorationFact {
11	  /** 0-indexed absolute line number in the document. */
12	  readonly lineNumber: number;
13	  /** Distance from the document root; top-level nodes are depth 0. */
14	  readonly depth: number;
15	  readonly isParagraphFirstLine: boolean;
16	}
17	
18	/**
19	 * Walks the parsed tree in document order (a node's own lines, then its
20	 * children — the same layout `nodeAtLine`/`startLine` assume: trailingGap
21	 * lines sit between a node's own lines and its children, and carry no
22	 * fact of their own).
23	 */
24	export function decorate(doc: OutlineDoc): LineDecorationFact[] {
25	  const facts: LineDecorationFact[] = [];
26	  let current = doc.preamble.length;
27	
28	  const walk = (node: OutlineNode, depth: number): void => {
29	    for (let i = 0; i < node.lines.length; i++) {
30	      facts.push({
31	        lineNumber: current + i,
32	        depth,
33	        isParagraphFirstLine: node.kind === 'paragraph' && i === 0,
34	      });
35	    }
