/**
 * Pure per-line decoration facts for outline mode's visual node chrome.
 * Scoped to paragraph nodes only: list items, headings, and atoms already
 * have their own native rendering (bullet/number, typography, block
 * chrome) with indentation math (hanging-indent text-indent + widget
 * buffers) that is fragile to override — a real-vault check found doing so
 * broke native list/checkbox indentation outright. Paragraphs are the one
 * node kind with zero native leader or indentation, so decorating them is
 * purely additive. No CM6 imports — decorations.ts is a thin adapter.
 */

import type { OutlineDoc, OutlineNode } from '../model';

export interface LineDecorationFact {
  /** 0-indexed absolute line number in the document. */
  readonly lineNumber: number;
  /** Distance from the document root; top-level nodes are depth 0. */
  readonly depth: number;
  /** True for every line of a paragraph node, not just its first. */
  readonly isParagraph: boolean;
  readonly isParagraphFirstLine: boolean;
}

/**
 * Walks the parsed tree in document order (a node's own lines, then its
 * children — the same layout `nodeAtLine`/`startLine` assume: trailingGap
 * lines sit between a node's own lines and its children, and carry no
 * fact of their own). Facts are emitted for every node — depth still
 * counts non-paragraph ancestors — but only paragraph facts are meant to
 * be rendered (see decorations.ts).
 */
export function decorate(doc: OutlineDoc): LineDecorationFact[] {
  const facts: LineDecorationFact[] = [];
  let current = doc.preamble.length;

  const walk = (node: OutlineNode, depth: number): void => {
    const isParagraph = node.kind === 'paragraph';
    for (let i = 0; i < node.lines.length; i++) {
      facts.push({
        lineNumber: current + i,
        depth,
        isParagraph,
        isParagraphFirstLine: isParagraph && i === 0,
      });
    }
    current += node.lines.length + node.trailingGap.length;
    node.children.forEach((child) => walk(child, depth + 1));
  };

  doc.children.forEach((node) => walk(node, 0));
  return facts;
}

