1	/**
2	 * CM6 adapter for outline mode's visual node chrome: indentation guides and
3	 * the paragraph leader marker. A `ViewPlugin` recomputes a `DecorationSet`
4	 * from `decorate(parse(...))` on every view update; all depth/marker logic
5	 * lives in the pure decorate.ts module. `refreshDecorations()` is the only
6	 * transaction this module ever dispatches, and it is content-empty — pure
7	 * rendering, never a document edit.
8	 */
9	
10	import {
11	  Decoration,
12	  ViewPlugin,
13	  type DecorationSet,
14	  type EditorView,
15	  type ViewUpdate,
16	} from '@codemirror/view';
17	import { editorInfoField } from 'obsidian';
18	import { parse } from '../parse';
19	import { decorate } from './decorate';
20	import type { ModeSource } from './keymap';
21	
22	function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
23	  const info = view.state.field(editorInfoField, false);
24	  const path = info?.file?.path;
25	  if (!path || !modes.isOutline(path)) return Decoration.none;
26	
27	  const doc = parse(view.state.doc.toString());
28	  const facts = decorate(doc);
29	  if (facts.length === 0) return Decoration.none;
30	
31	  const lineCount = view.state.doc.lines;
32	  const decorations = facts
33	    .filter((fact) => fact.lineNumber < lineCount)
34	    .map((fact) => {
35	      const line = view.state.doc.line(fact.lineNumber + 1);
36	      const classes = ['to-node-line'];
37	      if (fact.isParagraphFirstLine) classes.push('to-node-marker');
38	      return Decoration.line({
39	        attributes: {
40	          class: classes.join(' '),
41	          style: `--to-depth: ${fact.depth}`,
42	        },
43	      }).range(line.from);
44	    });
45	
46	  return Decoration.set(decorations, true);
47	}
48	
49	// Views currently carrying the extension, so an out-of-band mode toggle
50	// (plugin data, not a CM6 transaction) can be surfaced: `EditorView` is
51	// handed to the ViewPlugin by CM6 itself (a standard, fully public pattern),
52	// and `view.dispatch({})` is documented public API — no Obsidian internals.
53	const activeViews = new Set<EditorView>();
54	
55	export function decorationsExtension(modes: ModeSource) {
56	  return ViewPlugin.fromClass(
57	    class {
58	      decorations: DecorationSet;
59	
60	      constructor(private readonly view: EditorView) {
61	        activeViews.add(view);
62	        this.decorations = buildDecorations(view, modes);
63	      }
64	
65	      // Recompute on every view update, not just docChanged: mode toggles
66	      // arrive via refreshDecorations()'s empty dispatch, which is still a
67	      // ViewUpdate but carries no document change.
68	      update(update: ViewUpdate): void {
69	        this.decorations = buildDecorations(update.view, modes);
70	      }
71	
72	      destroy(): void {
73	        activeViews.delete(this.view);
74	      }
75	    },
76	    {
77	      decorations: (plugin) => plugin.decorations,
78	    },
79	  );
80	}
81	
82	/**
83	 * Force every live outline-decorated view to recompute. Outline mode lives
84	 * in plugin data, entirely outside CM6 state, so toggling it produces no
85	 * transaction on its own — call this right after a toggle so the change is
86	 * visible immediately instead of waiting for the next incidental edit.
87	 */
88	export function refreshDecorations(): void {
89	  for (const view of activeViews) view.dispatch({});
90	}
