2	 * CM6 adapter for outline mode's visual node chrome: paragraph indentation
3	 * and the paragraph leader marker. Scoped to paragraph lines only — a
4	 * real-vault check found overriding list-item/heading line styling broke
5	 * their native hanging-indent math (checkbox/bullet layout went visibly
6	 * wrong), so this never touches lines outside a paragraph node (see
7	 * decorate.ts). A `ViewPlugin` recomputes a `DecorationSet` from
8	 * `decorate(parse(...))` on every view update; all depth/marker logic lives
9	 * in the pure decorate.ts module. `refreshDecorations()` is the only
10	 * transaction this module ever dispatches, and it is content-empty — pure
11	 * rendering, never a document edit.
12	 */
13	
14	import {
15	  Decoration,
16	  ViewPlugin,
17	  type DecorationSet,
18	  type EditorView,
19	  type ViewUpdate,
20	} from '@codemirror/view';
21	import { editorInfoField } from 'obsidian';
22	import { parse } from '../parse';
23	import { decorate } from './decorate';
24	import type { ModeSource } from './keymap';
25	
26	function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
27	  const info = view.state.field(editorInfoField, false);
28	  const path = info?.file?.path;
29	  if (!path || !modes.isOutline(path)) return Decoration.none;
30	
31	  const doc = parse(view.state.doc.toString());
32	  const facts = decorate(doc);
33	  if (facts.length === 0) return Decoration.none;
34	
35	  const lineCount = view.state.doc.lines;
36	  const decorations = facts
37	    .filter((fact) => fact.isParagraph && fact.lineNumber < lineCount)
38	    .map((fact) => {
39	      const line = view.state.doc.line(fact.lineNumber + 1);
40	      const classes = ['to-node-line'];
41	      if (fact.isParagraphFirstLine) classes.push('to-node-marker');
42	      return Decoration.line({
43	        attributes: {
44	          class: classes.join(' '),
45	          style: `--to-depth: ${fact.depth}`,
46	        },
47	      }).range(line.from);
48	    });
49	
50	  return Decoration.set(decorations, true);
51	}
52	
53	// Views currently carrying the extension, so an out-of-band mode toggle
54	// (plugin data, not a CM6 transaction) can be surfaced: `EditorView` is
55	// handed to the ViewPlugin by CM6 itself (a standard, fully public pattern),
56	// and `view.dispatch({})` is documented public API — no Obsidian internals.
57	const activeViews = new Set<EditorView>();
58	
59	export function decorationsExtension(modes: ModeSource) {
60	  return ViewPlugin.fromClass(
61	    class {
62	      decorations: DecorationSet;
63	
64	      constructor(private readonly view: EditorView) {
65	        activeViews.add(view);
66	        this.decorations = buildDecorations(view, modes);
67	      }
68	
69	      // Recompute on every view update, not just docChanged: mode toggles
70	      // arrive via refreshDecorations()'s empty dispatch, which is still a
71	      // ViewUpdate but carries no document change.
72	      update(update: ViewUpdate): void {
73	        this.decorations = buildDecorations(update.view, modes);
74	      }
75	
76	      destroy(): void {
77	        activeViews.delete(this.view);
78	      }
79	    },
80	    {
81	      decorations: (plugin) => plugin.decorations,
82	    },
83	  );
84	}
85	
86	/**
87	 * Force every live outline-decorated view to recompute. Outline mode lives
88	 * in plugin data, entirely outside CM6 state, so toggling it produces no
89	 * transaction on its own — call this right after a toggle so the change is
90	 * visible immediately instead of waiting for the next incidental edit.
91	 */
92	export function refreshDecorations(): void {
93	  for (const view of activeViews) view.dispatch({});
94	}
