1	/**
2	 * Pure per-line decoration facts for outline mode's visual node chrome.
3	 * Every node kind is decorated — headings, paragraphs, list items, and
4	 * atoms all get the same tree-depth indentation and a consistent, prominent
5	 * marker, so the tree reads as one hierarchy regardless of how a node is
6	 * encoded in markdown. List items already have a native marker glyph
7	 * (bullet/number) and native hanging-indent positioning for it; rather than
8	 * replacing that mechanism, decorations.ts reuses it — the SAME
9	 * `padding-left`/`text-indent` pair Obsidian already uses to hang bullets
10	 * is applied uniformly (one fixed unit, not Obsidian's own per-level
11	 * values) to every kind, so list bullets/checkboxes hang correctly at our
12	 * depth-based position without needing separate positioning logic, and
13	 * kinds without a native marker (paragraphs, headings, atoms) get a
14	 * `::before` glyph that hangs the exact same way. No CM6 imports —
15	 * decorations.ts is a thin adapter.
16	 */
17	
18	import type { OutlineDoc, OutlineNode } from '../model';
19	
20	export interface LineDecorationFact {
21	  /** 0-indexed absolute line number in the document. */
22	  readonly lineNumber: number;
23	  /** Distance from the document root; top-level nodes are depth 0. */
24	  readonly depth: number;
25	  /** True only for a node's own first line — carries the hang + marker. */
26	  readonly isFirstLine: boolean;
27	  /**
28	   * True for list-item first lines: they already have a native marker
29	   * glyph (bullet/number) that should be restyled in place, not
30	   * supplemented with our own `::before` marker.
31	   */
32	  readonly hasNativeMarker: boolean;
33	}
34	
35	/**
36	 * Walks the parsed tree in document order (a node's own lines, then its
37	 * children — the same layout `nodeAtLine`/`startLine` assume: trailingGap
38	 * lines sit between a node's own lines and its children, and carry no fact
39	 * of their own).
40	 */
41	export function decorate(doc: OutlineDoc): LineDecorationFact[] {
42	  const facts: LineDecorationFact[] = [];
43	  let current = doc.preamble.length;
44	
45	  const walk = (node: OutlineNode, depth: number): void => {
46	    for (let i = 0; i < node.lines.length; i++) {
47	      facts.push({
48	        lineNumber: current + i,
49	        depth,
50	        isFirstLine: i === 0,
51	        hasNativeMarker: node.kind === 'list-item' && i === 0,
52	      });
53	    }
54	    current += node.lines.length + node.trailingGap.length;
55	    node.children.forEach((child) => walk(child, depth + 1));
56	  };
57	
58	  doc.children.forEach((node) => walk(node, 0));
59	  return facts;
60	}
61

