1	/**
2	 * CM6 adapter for outline mode's visual node chrome: uniform tree-depth
3	 * indentation and a consistent marker across every node kind. A `ViewPlugin`
4	 * recomputes a `DecorationSet` from `decorate(parse(...))` on every view
5	 * update; all depth/marker logic lives in the pure decorate.ts module.
6	 * `refreshDecorations()` is the only transaction this module ever
7	 * dispatches, and it is content-empty — pure rendering, never a document
8	 * edit. See design.md D9/D10 for why every kind gets the same
9	 * `padding-left`/`text-indent` pair (Obsidian's own bullet-hanging
10	 * mechanism, reused rather than fought).
11	 */
12	
13	import {
14	  Decoration,
15	  ViewPlugin,
16	  type DecorationSet,
17	  type EditorView,
18	  type ViewUpdate,
19	} from '@codemirror/view';
20	import { editorInfoField } from 'obsidian';
21	import { parse } from '../parse';
22	import { decorate } from './decorate';
23	import type { ModeSource } from './keymap';
24	
25	function buildDecorations(view: EditorView, modes: ModeSource): DecorationSet {
26	  const info = view.state.field(editorInfoField, false);
27	  const path = info?.file?.path;
28	  if (!path || !modes.isOutline(path)) return Decoration.none;
29	
30	  const doc = parse(view.state.doc.toString());
31	  const facts = decorate(doc);
32	  if (facts.length === 0) return Decoration.none;
33	
34	  const lineCount = view.state.doc.lines;
35	  const decorations = facts
36	    .filter((fact) => fact.lineNumber < lineCount)
37	    .map((fact) => {
38	      const line = view.state.doc.line(fact.lineNumber + 1);
39	      const classes = ['to-node-line'];
40	      if (fact.isFirstLine) {
41	        classes.push('to-node-first');
42	        classes.push(fact.hasNativeMarker ? 'to-node-native-marker' : 'to-node-marker');
43	      }
44	      return Decoration.line({
45	        attributes: {
46	          class: classes.join(' '),
47	          style: `--to-depth: ${fact.depth}`,
48	        },
49	      }).range(line.from);
50	    });
51	
52	  return Decoration.set(decorations, true);
53	}
54	
55	// Views currently carrying the extension, so an out-of-band mode toggle
56	// (plugin data, not a CM6 transaction) can be surfaced: `EditorView` is
57	// handed to the ViewPlugin by CM6 itself (a standard, fully public pattern),
58	// and `view.dispatch({})` is documented public API — no Obsidian internals.
59	const activeViews = new Set<EditorView>();
60	
61	export function decorationsExtension(modes: ModeSource) {
62	  return ViewPlugin.fromClass(
63	    class {
64	      decorations: DecorationSet;
65	
66	      constructor(private readonly view: EditorView) {
67	        activeViews.add(view);
68	        this.decorations = buildDecorations(view, modes);
69	      }
70	
71	      // Recompute on every view update, not just docChanged: mode toggles
72	      // arrive via refreshDecorations()'s empty dispatch, which is still a
73	      // ViewUpdate but carries no document change.
74	      update(update: ViewUpdate): void {
75	        this.decorations = buildDecorations(update.view, modes);
76	      }
77	
78	      destroy(): void {
79	        activeViews.delete(this.view);
80	      }
81	    },
82	    {
83	      decorations: (plugin) => plugin.decorations,
84	    },
85	  );
86	}
87	
88	/**
89	 * Force every live outline-decorated view to recompute. Outline mode lives
90	 * in plugin data, entirely outside CM6 state, so toggling it produces no
91	 * transaction on its own — call this right after a toggle so the change is
92	 * visible immediately instead of waiting for the next incidental edit.
93	 */
94	export function refreshDecorations(): void {
95	  for (const view of activeViews) view.dispatch({});
96	}
97

