import * as h from '../helpers.js';

describe('visual check', function () {
  it('dumps list-item-with-children HTML', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await h.createNote('Scratch/fold-check.md', '- alpha\n  - beta\n- gamma\n');
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(300);

    const html = await browser.execute(() =>
      document.querySelector('.workspace-leaf.mod-active .cm-content')?.innerHTML,
    );
    console.log('DEBUG html', html);
    expect(true).toBe(true);
  });
});

/** Scratch: diagnostic — fold indicator rendered geometry vs our bullet dot. */
import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

describe('visual check', function () {
  it('measures fold indicator vs bullet dot', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await h.createNote('Scratch/fold-check.md', '- alpha\n  - beta\n');
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(300);

    const info = await browser.execute(() => {
      const fold = document.querySelector('.workspace-leaf.mod-active .cm-fold-indicator');
      const bullet = document.querySelector('.workspace-leaf.mod-active .list-bullet');
      const foldRect = fold?.getBoundingClientRect();
      const bulletRect = bullet?.getBoundingClientRect();
      const foldCs = fold ? getComputedStyle(fold) : null;
      return {
        foldRect: foldRect && { x: foldRect.x, y: foldRect.y, w: foldRect.width, h: foldRect.height },
        bulletRect: bulletRect && { x: bulletRect.x, y: bulletRect.y, w: bulletRect.width, h: bulletRect.height },
        foldPosition: foldCs?.position,
        foldOpacity: foldCs?.opacity,
        foldDisplay: foldCs?.display,
      };
    });
    console.log('DEBUG info', JSON.stringify(info, null, 2));
    expect(true).toBe(true);
  });
});

