    );
  });
});

/** Scratch: diagnostic — full computed style of list-bullet::before. */
import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

describe('visual check', function () {
  it('dumps list-bullet::before full style', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await h.createNote('Scratch/bullet-check2.md', '- alpha\n- beta\n');
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await browser.pause(300);

    const info = await browser.execute(() => {
      const bullet = document.querySelector('.workspace-leaf.mod-active .list-bullet');
      if (!bullet) return null;
      const before = getComputedStyle(bullet, '::before');
      const props = [
        'content', 'width', 'height', 'backgroundColor', 'borderRadius',
        'display', 'position', 'top', 'left', 'color', 'fontSize',
      ];
      const result = {};
      for (const p of props) result[p] = (before)[p];
      return result;
    });
    console.log('DEBUG beforeStyle', JSON.stringify(info, null, 2));
    expect(true).toBe(true);
  });
});

/** Scratch: diagnostic — zoomed screenshot of bullet markers. */
import { browser } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

describe('visual check', function () {
  it('screenshots zoomed bullets', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await h.createNote(
      'Scratch/bullet-isolated.md',
      '- no children\n- has children\n  - child one\n  - child two\n- also no children\n',
    );
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await h.setCursor(4, 4); // move cursor off the first line
    await browser.pause(300);
    await h.dismissNotices();
    await browser.execute(() => {
      (document.body.style as any).zoom = '4';
    });
    await browser.pause(300);
    await browser.saveScreenshot(
      '/private/tmp/claude-502/-Users-laughedelic-Code-obsidian-true-outliner/2746a754-e8cd-4635-ad29-f198bf4c84cf/scratchpad/bullet-zoomed.png',
    );
  });
});

/** Scratch: diagnostic — enumerate all descendants + pseudo content/rects. */
import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

describe('visual check', function () {
  it('enumerates all elements in the "has children" line', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();
    await h.createNote(
      'Scratch/bullet-isolated.md',
      '- no children\n- has children\n  - child one\n',
    );
    await h.toggleOutlineMode();
    await h.waitForNotice('Outline mode on');
    await h.setCursor(2, 2);
    await browser.pause(300);

    const info = await browser.execute(() => {
      const lines = Array.from(
        document.querySelectorAll('.workspace-leaf.mod-active .cm-content > .cm-line'),
      );
      const line = lines.find((l) => l.textContent?.includes('has children'));
      if (!line) return null;
      const all = [line, ...Array.from(line.querySelectorAll('*'))];
      return all.map((el) => {
        const rect = el.getBoundingClientRect();
        const before = getComputedStyle(el, '::before');
        const after = getComputedStyle(el, '::after');
        return {
          tag: el.tagName,
          className: (el as HTMLElement).className,
          rect: { x: Math.round(rect.x), y: Math.round(rect.y), w: Math.round(rect.width), h: Math.round(rect.height) },
          beforeContent: before.content,
          beforeBg: before.backgroundColor,
          afterContent: after.content,
          afterBg: after.backgroundColor,
        };
      });
    });
    console.log('DEBUG elements', JSON.stringify(info, null, 2));
    expect(true).toBe(true);
  });
});

