/** Scratch: not part of the suite — final repro screenshots. */
import { browser } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as h from '../helpers.js';

const JOURNAL_MD = [
  '# 2026-07-08',
  '',
  'Better day. The kind where things click.',
  '',
  'Errands before the heat sets in.',
  '',
  '- [x] picked up paint samples',
  '- [x] returned the library book',
  "- [ ] drop off the drill at Tom's",
  '',
  'Aurora work went deep today.',
  '',
  "- users don't scan the dashboard top to bottom",
  '- which means the severity column needs to move left',
  '- prototype this before Thursday standup',
  '  - borrow the triage mockup from Priya',
  '  - keep the timestamp format consistent',
  '',
  'Called mom. She wants to visit before summer evaporates.',
  '',
].join('\n');

const NESTED_MD = [
  '# 2026-07-12',
  'Long Saturday. The reclaimed materials search paid off.',
  '- kitchen',
  '  - found 4m² of terracotta tile at the salvage yard',
  '    - imperfect in the best way',
  '    - 40% of the price of new',
  '  - Sarah is converted.',
  '  - measured twice:',
  '    1. counter run: 3.2m',
  '    2. splash zone: 1.8m',
  '    3. floor patch by the door',
  '- training',
  '  - 14k long run, easy pace',
  '  - new route through the park',
  '    - shade the whole way',
  '- reading',
  '  - Norman on affordances, the door-handle chapter',
  '',
].join('\n');

const CODE_MD = [
  '# Technical notes',
  '',
  '- The severity sort must be stable or rows jump under the cursor',
  '',
  '```js',
  'alarms.sort((a, b) =>',
  '  b.severity - a.severity || a.firstSeen - b.firstSeen',
  ');',
  '```',
  '',
  '## Edge case: acknowledged-but-recurring',
  '',
  '- Deep-filed note (skipped heading levels on purpose): resetting',
  '  its acknowledgement window should keep its row pinned',
  '',
].join('\n');

describe('visual check', function () {
  it('screenshots the reported repro shapes', async function () {
    await obsidianPage.resetVault();
    await h.resetPluginState();

    for (const [name, md] of [
      ['journal-repro', JOURNAL_MD],
      ['nested-repro', NESTED_MD],
      ['code-repro', CODE_MD],
    ] as const) {
      await h.createNote(`Scratch/${name}.md`, md);
      await h.toggleOutlineMode();
      await h.waitForNotice('Outline mode on');
      await h.setCursor(md.split('\n').length - 1, 0);
      await browser.pause(300);
      await h.dismissNotices();
      await browser.pause(200);
      await browser.saveScreenshot(
        `/private/tmp/claude-502/-Users-laughedelic-Code-obsidian-true-outliner/2746a754-e8cd-4635-ad29-f198bf4c84cf/scratchpad/v5-${name}.png`,
      );
    }
  });
});

